ui.debug.addRules("numcity",[{rules:"Place a positive number in every cell.\n1. Groups of identical numbers are called districts, and each outlined region is called a city. All identical numbers in each city must be connected.\n2. The largest district in each city is marked with a 1, the second-largest is marked with a 2, and so on. Districts in a city cannot have the same size.\n3. Identical numbers cannot be orthogonally adjacent across city borders.",history:"This genre first appeared in Puzzle Communication Nikoli vol. 175."},{rules:"1. 盤面にある太線で区切られた部分(県)を、それぞれいくつかの小さな領域(市)に分割しましょう。\n2. 県は、点線の上にタテヨコに線を引いて市に分割します。分割せずに1つの市だけでできた県があってもかまいません。\n3. 数字はその市が県内で何番目に大きい市であるかを表し、すべてのマスに1つずつ数字が入ります。1つの県内に同じ大きさの市ができてはいけません、\n4. 同じ数字が太線(県境)をはさんでタテヨコに隣り合ってはいけません。",history:"パズル通信ニコリ vol.175より"}]),ui.debug.addDebugData("numcity",{url:"4/4/j2i13l4i0s08",failcheck:[["nmDivide","pzprv3/numcity/4/4/. . . . /2 . . . /1 3 . . /. . . . /. . . . /. 2 . . /. . . . /. . 1 1 /0 0 X /0 0 X /0 0 X /0 0 0 /X X X 0 /0 0 0 0 /0 0 0 X /"],["nmOrder","pzprv3/numcity/4/4/. . . . /2 . . . /1 3 . . /. . . . /. . . 1 /. 2 . 2 /. . . 2 /1 1 . . /0 0 X /0 0 X /0 0 X /0 0 0 /X X X 0 /0 0 0 0 /0 0 0 X /"],["nmNoSequence","pzprv3/numcity/4/4/. . . . /2 . . . /1 3 . . /. . . . /. . . 2 /. 2 . . /. . . . /1 1 . . /0 0 X /0 0 X /0 0 X /0 0 0 /X X X 0 /0 0 0 0 /0 0 0 X /"],["nmAdjacent","pzprv3/numcity/4/4/. . . . /2 . . . /1 3 . . /. . . . /1 1 2 1 /. 2 2 1 /. . 3 2 /1 1 1 4 /0 0 X /0 0 X /0 0 X /0 0 0 /X X X 0 /0 0 0 0 /0 0 0 X /"],["ceNoNum","pzprv3/numcity/4/4/. . . . /2 . . . /1 3 . . /. . . . /. . . . /. 2 . . /. . . . /1 1 . . /0 0 X /0 0 X /0 0 X /0 0 0 /X X X 0 /0 0 0 0 /0 0 0 X /"],[null,"pzprv3/numcity/4/4/. . . . /2 . . . /1 3 . . /. . . . /1 1 1 2 /. 2 2 1 /. . 3 1 /1 1 1 4 /0 0 X /0 0 X /0 0 X /0 0 0 /X X X 0 /0 0 0 0 /0 0 0 X /"]],inputs:[]});
